+    let err = TrustTransitionError::RiskTooHigh {
+        target: ExtensionTrustState::Restricted,
+        risk_score: 10,
+        max_allowed: 30,
+    };
+    let msg = format!("{err}");
+    assert!(msg.contains("10"));
